namespace TestWidgetUtils {

    // Forward declaration of test wrapper from ui_widgets_core.cpp
    extern "C" void test_widget_reset_state();
    extern "C" WidgetArena* test_widget_get_arena();

    // Reset global widget state between tests
    void reset_widget_state() {
        test_widget_reset_state();
    }

    // Get the global widget arena
    WidgetArena& get_global_arena() {
        return *test_widget_get_arena();
    }

    // Simple test widget with configurable behavior
    struct TestWidget : Widget {
        bool mouse_enter_called = false;
        bool mouse_leave_called = false;
        bool mouse_down_called = false;
        bool mouse_up_called = false;
        bool key_down_called = false;
        bool focus_called = false;
        bool blur_called = false;
        int render_count = 0;
        int consume_events = 0;  // 0=don't consume, 1=consume mouse, 2=consume keyboard

        bool on_mouse_enter() override {
            mouse_enter_called = true;
            return (consume_events == 1);
        }

        bool on_mouse_leave() override {
            mouse_leave_called = true;
            return (consume_events == 1);
        }

        bool on_mouse_down(float x, float y, int button) override {
            (void)x; (void)y;
            mouse_down_called = true;
            return button == 0 && (consume_events == 1);
        }

        bool on_mouse_up(float x, float y, int button) override {
            (void)x; (void)y;
            mouse_up_called = true;
            return button == 0 && (consume_events == 1);
        }

        bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
            (void)vk; (void)ctrl; (void)shift; (void)alt;
            key_down_called = true;
            return (consume_events == 2);
        }

        void render(RenderContext& ctx) override {
            (void)ctx;
            render_count++;
        }

        bool on_focus() override {
            focus_called = true;
            return true;
        }

        bool on_blur() override {
            blur_called = true;
            return true;
        }
    };

    // Create a basic test widget with specific dimensions
    TestWidget* create_test_widget(float x = 0.0f, float y = 0.0f, float width = 100.0f, float height = 50.0f) {
        auto* w = get_global_arena().create<TestWidget>();
        w->rect.x = x;
        w->rect.y = y;
        w->rect.width = width;
        w->rect.height = height;
        w->preferred_width = width;
        w->preferred_height = height;
        return w;
    }

    // Create a FlexContainer with given direction and child count
    FlexContainer* create_flex_container(FlexDirection dir = FlexDirection::Column, int child_count = 0) {
        auto* container = get_global_arena().create<FlexContainer>();
        container->direction = dir;
        container->rect.x = 0.0f;
        container->rect.y = 0.0f;
        container->rect.width = 200.0f;
        container->rect.height = 200.0f;

        for (int i = 0; i < child_count; i++) {
            auto* child = create_test_widget();
            child->preferred_width = 50.0f;
            child->preferred_height = 30.0f;
            widget_add_child(container, child);
        }

        return container;
    }

    // Assert widget has expected layout
    void assert_widget_layout(Widget* w, float x, float y, float width, float height) {
        TEST_ASSERT_EQ(w->rect.x, x);
        TEST_ASSERT_EQ(w->rect.y, y);
        TEST_ASSERT_EQ(w->rect.width, width);
        TEST_ASSERT_EQ(w->rect.height, height);
    }

    // Assert widget has specific flags set
    void assert_widget_flags(Widget* w, uint16_t expected_flags) {
        TEST_ASSERT_EQ(w->flags & expected_flags, expected_flags);
    }

    // Assert widget does NOT have specific flags
    void assert_widget_not_flags(Widget* w, uint16_t unwanted_flags) {
        TEST_ASSERT_EQ(w->flags & unwanted_flags, 0);
    }

} // namespace TestWidgetUtils

