TEST(widget_event_hit_test_single_widget) {
    using namespace TestWidgetUtils;

    reset_widget_state();
    auto* w = create_test_widget(10.0f, 20.0f, 100.0f, 50.0f);

    // Point inside widget
    TEST_ASSERT_TRUE(w->hit_test(50.0f, 40.0f));

    // Point outside widget
    TEST_ASSERT_FALSE(w->hit_test(5.0f, 40.0f));  // Left of widget
    TEST_ASSERT_FALSE(w->hit_test(50.0f, 10.0f)); // Above widget
    TEST_ASSERT_FALSE(w->hit_test(120.0f, 40.0f)); // Right of widget
    TEST_ASSERT_FALSE(w->hit_test(50.0f, 80.0f)); // Below widget
}

TEST(widget_event_hit_test_nested_children) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    // Create parent-child hierarchy
    auto* parent = create_test_widget(0.0f, 0.0f, 200.0f, 200.0f);
    auto* child1 = create_test_widget(10.0f, 10.0f, 80.0f, 60.0f);
    auto* child2 = create_test_widget(100.0f, 50.0f, 80.0f, 60.0f);

    widget_add_child(parent, child1);
    widget_add_child(parent, child2);

    // Create event dispatcher
    EventDispatcher dispatcher;
    dispatcher.root = parent;

    // Hit test should find deepest widget
    Widget* hit = dispatcher.hit_test(parent, 50.0f, 40.0f);
    TEST_ASSERT_EQ(hit, child1);

    hit = dispatcher.hit_test(parent, 140.0f, 80.0f);
    TEST_ASSERT_EQ(hit, child2);

    // Hit in parent but not in any child
    hit = dispatcher.hit_test(parent, 90.0f, 40.0f);
    TEST_ASSERT_EQ(hit, parent);
}

