TEST(widget_event_mouse_hover_propagation) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* parent = create_test_widget(0.0f, 0.0f, 200.0f, 200.0f);
    auto* child = create_test_widget(50.0f, 50.0f, 100.0f, 100.0f);
    widget_add_child(parent, child);

    EventDispatcher dispatcher;
    dispatcher.root = parent;

    // Move mouse into child (child gets hovered, parent does not)
    dispatcher.dispatch_mouse_move(100.0f, 100.0f);
    TEST_ASSERT_TRUE(child->is_hovered());
    // Parent is not automatically hovered when child is hovered
    // (hovered flag is only set on the actual hit target)
    TEST_ASSERT_TRUE(!parent->is_hovered() || dispatcher.hovered == child);
}

