TEST(widget_layout_measure_fixed_size) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* w = create_test_widget();
    w->width_mode = SizeMode::Fixed;
    w->height_mode = SizeMode::Fixed;
    w->preferred_width = 100.0f;
    w->preferred_height = 50.0f;

    LayoutConstraints constraints = { 0.0f, 1000.0f, 0.0f, 1000.0f };
    w->measure(constraints);

    // Fixed size should use preferred dimensions
    TEST_ASSERT_EQ(w->rect.width, 100.0f);
    TEST_ASSERT_EQ(w->rect.height, 50.0f);
}

TEST(widget_layout_measure_fill_expands) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* w = create_test_widget();
    w->width_mode = SizeMode::Fill;
    w->height_mode = SizeMode::Fill;
    // Set preferred to large value so Fill can expand to max
    w->preferred_width = 1000.0f;
    w->preferred_height = 1000.0f;

    LayoutConstraints constraints = { 100.0f, 500.0f, 80.0f, 400.0f };
    w->measure(constraints);

    // Fill mode (with large preferred) should be clamped to max constraint
    TEST_ASSERT_EQ(w->rect.width, 500.0f);
    TEST_ASSERT_EQ(w->rect.height, 400.0f);
}

