TEST(widget_layout_flex_row_flex_children_expand) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* container = create_flex_container(FlexDirection::Row, 2);

    // Make both children flexible
    int idx = 0;
    for (Widget* child = container->first_child; child; child = child->next_sibling) {
        child->preferred_width = 50.0f;  // Small base size
        child->flex = 1.0f;  // Equal flex
        idx++;
    }

    // Measure first to get natural size
    LayoutConstraints constraints = { 0.0f, 500.0f, 0.0f, 500.0f };
    container->measure(constraints);

    // Then manually set container size (measure() overwrites rect.width/height)
    container->rect.width = 300.0f;
    container->rect.height = 100.0f;

    container->layout();

    // Both children should expand equally to fill available space
    // Available = 300, total_flex = 2, each child gets (1/2) * 300 = 150
    Widget* child1 = container->first_child;
    Widget* child2 = child1->next_sibling;

    float expected_width = 150.0f;
    TEST_ASSERT_EQ(child1->rect.width, expected_width);
    TEST_ASSERT_EQ(child2->rect.width, expected_width);
}

