TEST(widget_layout_nested_flex_containers) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    // Outer row container
    auto* outer = create_flex_container(FlexDirection::Row, 2);
    outer->rect.width = 400.0f;
    outer->rect.height = 200.0f;

    // Replace children with column containers
    Widget* child1 = outer->first_child;
    Widget* child2 = child1->next_sibling;

    // Create nested column container for first child
    auto* nested = create_flex_container(FlexDirection::Column, 2);
    nested->rect.width = 150.0f;
    nested->rect.height = 150.0f;

    // Swap child1 with nested container
    widget_remove_child(outer, child1);
    widget_add_child(outer, nested);

    LayoutConstraints constraints = { 0.0f, 500.0f, 0.0f, 500.0f };
    outer->measure(constraints);
    outer->layout();

    // Nested container should be laid out
    TEST_ASSERT_TRUE(nested->rect.width > 0.0f);
    TEST_ASSERT_TRUE(nested->rect.height > 0.0f);
}

