TEST(widget_virt_viewport_bounds_initial) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    // Create a simple test container to simulate virtualized list viewport
    auto* viewport = create_test_widget(0.0f, 0.0f, 300.0f, 400.0f);

    // Initial bounds should match rect
    TEST_ASSERT_EQ(viewport->rect.x, 0.0f);
    TEST_ASSERT_EQ(viewport->rect.y, 0.0f);
    TEST_ASSERT_EQ(viewport->rect.width, 300.0f);
    TEST_ASSERT_EQ(viewport->rect.height, 400.0f);
}

TEST(widget_virt_viewport_bounds_updated) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* viewport = create_test_widget(0.0f, 0.0f, 300.0f, 400.0f);

    // Simulate viewport bounds update
    viewport->rect.x = 50.0f;
    viewport->rect.y = 100.0f;
    viewport->rect.width = 350.0f;
    viewport->rect.height = 500.0f;

    TEST_ASSERT_EQ(viewport->rect.x, 50.0f);
    TEST_ASSERT_EQ(viewport->rect.y, 100.0f);
    TEST_ASSERT_EQ(viewport->rect.width, 350.0f);
    TEST_ASSERT_EQ(viewport->rect.height, 500.0f);
}

TEST(widget_virt_item_above_viewport_hidden) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    // Viewport from y=100 to y=500
    auto* viewport = create_test_widget(0.0f, 100.0f, 300.0f, 400.0f);

    // Item above viewport (y=0 to y=50)
    auto* item = create_test_widget(0.0f, 0.0f, 100.0f, 50.0f);

    // Item should not be visible in viewport
    TEST_ASSERT_FALSE(item->rect.y >= viewport->rect.y &&
                      item->rect.y + item->rect.height <= viewport->rect.y + viewport->rect.height);
}

TEST(widget_virt_item_below_viewport_hidden) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    // Viewport from y=100 to y=500
    auto* viewport = create_test_widget(0.0f, 100.0f, 300.0f, 400.0f);

    // Item below viewport (y=600 to y=650)
    auto* item = create_test_widget(0.0f, 600.0f, 100.0f, 50.0f);

    // Item should not be visible in viewport
    TEST_ASSERT_FALSE(item->rect.y >= viewport->rect.y &&
                      item->rect.y + item->rect.height <= viewport->rect.y + viewport->rect.height);
}

TEST(widget_virt_item_partial_in_viewport_visible) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    // Viewport from y=100 to y=500
    auto* viewport = create_test_widget(0.0f, 100.0f, 300.0f, 400.0f);

    // Item partially in viewport (y=80 to y=150)
    auto* item = create_test_widget(0.0f, 80.0f, 100.0f, 70.0f);

    // Item should overlap viewport
    bool overlaps = (item->rect.y < viewport->rect.y + viewport->rect.height) &&
                    (item->rect.y + item->rect.height > viewport->rect.y);
    TEST_ASSERT_TRUE(overlaps);
}

TEST(widget_virt_all_items_outside_viewport) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* viewport = create_test_widget(0.0f, 100.0f, 300.0f, 400.0f);

    // All items outside viewport
    auto* item1 = create_test_widget(0.0f, -100.0f, 100.0f, 50.0f);  // Above
    auto* item2 = create_test_widget(0.0f, 600.0f, 100.0f, 50.0f);   // Below

    bool item1_visible = item1->rect.y >= viewport->rect.y &&
                         item1->rect.y + item1->rect.height <= viewport->rect.y + viewport->rect.height;
    bool item2_visible = item2->rect.y >= viewport->rect.y &&
                         item2->rect.y + item2->rect.height <= viewport->rect.y + viewport->rect.height;

    TEST_ASSERT_FALSE(item1_visible);
    TEST_ASSERT_FALSE(item2_visible);
}

TEST(widget_virt_scroll_to_item_above) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* viewport = create_test_widget(0.0f, 100.0f, 300.0f, 400.0f);

    // Item above viewport
    auto* item = create_test_widget(0.0f, 50.0f, 100.0f, 50.0f);

    // To scroll to item, viewport top would need to move up
    float viewport_bottom = viewport->rect.y + viewport->rect.height;
    float item_bottom = item->rect.y + item->rect.height;

    TEST_ASSERT_TRUE(item->rect.y < viewport->rect.y);
}

TEST(widget_virt_scroll_to_item_below) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* viewport = create_test_widget(0.0f, 100.0f, 300.0f, 400.0f);

    // Item below viewport
    auto* item = create_test_widget(0.0f, 600.0f, 100.0f, 50.0f);

    // To scroll to item, viewport top would need to move down
    TEST_ASSERT_TRUE(item->rect.y > viewport->rect.y + viewport->rect.height);
}

