TEST(widget_focus_set_focus_updates_flags) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* w = create_test_widget();
    w->flags |= WidgetFlags::Focusable;

    EventDispatcher dispatcher;
    dispatcher.root = w;

    dispatcher.set_focus(w);

    TEST_ASSERT_TRUE(w->is_focused());
    TEST_ASSERT_TRUE(w->focus_called);
    TEST_ASSERT_EQ(dispatcher.focused, w);
}

TEST(widget_focus_clear_focus_removes_flags) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* w = create_test_widget();
    w->flags |= WidgetFlags::Focusable;

    EventDispatcher dispatcher;
    dispatcher.root = w;

    dispatcher.set_focus(w);
    TEST_ASSERT_TRUE(w->is_focused());

    dispatcher.set_focus(nullptr);

    TEST_ASSERT_FALSE(w->is_focused());
    TEST_ASSERT_TRUE(w->blur_called);
    TEST_ASSERT_EQ(dispatcher.focused, (Widget*)nullptr);
}

TEST(widget_focus_tab_forward_cycles) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* parent = create_test_widget(0.0f, 0.0f, 200.0f, 200.0f);
    auto* child1 = create_test_widget(0.0f, 0.0f, 50.0f, 50.0f);
    auto* child2 = create_test_widget(50.0f, 0.0f, 50.0f, 50.0f);
    auto* child3 = create_test_widget(100.0f, 0.0f, 50.0f, 50.0f);

    child1->flags |= WidgetFlags::Focusable;
    child2->flags |= WidgetFlags::Focusable;
    child3->flags |= WidgetFlags::Focusable;

    widget_add_child(parent, child1);
    widget_add_child(parent, child2);
    widget_add_child(parent, child3);

    EventDispatcher dispatcher;
    dispatcher.root = parent;

    // Focus first child
    dispatcher.set_focus(child1);
    TEST_ASSERT_EQ(dispatcher.focused, child1);

    // Tab forward (shift=false) should go to next focusable widget
    dispatcher.tab_navigate(false);
    TEST_ASSERT_EQ(dispatcher.focused, child2);

    dispatcher.tab_navigate(false);
    TEST_ASSERT_EQ(dispatcher.focused, child3);

    // Tab from last should cycle to first
    dispatcher.tab_navigate(false);
    TEST_ASSERT_EQ(dispatcher.focused, child1);
}

TEST(widget_focus_tab_backward_cycles) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* parent = create_test_widget(0.0f, 0.0f, 200.0f, 200.0f);
    auto* child1 = create_test_widget(0.0f, 0.0f, 50.0f, 50.0f);
    auto* child2 = create_test_widget(50.0f, 0.0f, 50.0f, 50.0f);
    auto* child3 = create_test_widget(100.0f, 0.0f, 50.0f, 50.0f);

    child1->flags |= WidgetFlags::Focusable;
    child2->flags |= WidgetFlags::Focusable;
    child3->flags |= WidgetFlags::Focusable;

    widget_add_child(parent, child1);
    widget_add_child(parent, child2);
    widget_add_child(parent, child3);

    EventDispatcher dispatcher;
    dispatcher.root = parent;

    dispatcher.set_focus(child1);

    // Tab backward (shift=true) should go to previous focusable
    dispatcher.tab_navigate(true);
    TEST_ASSERT_EQ(dispatcher.focused, child3);

    dispatcher.tab_navigate(true);
    TEST_ASSERT_EQ(dispatcher.focused, child2);
}

TEST(widget_focus_arrow_in_focus_group) {
    using namespace TestWidgetUtils;

    reset_widget_state();

    auto* parent = create_test_widget(0.0f, 0.0f, 200.0f, 200.0f);
    parent->flags |= WidgetFlags::FocusGroup;

    auto* child1 = create_test_widget(0.0f, 0.0f, 50.0f, 50.0f);
    auto* child2 = create_test_widget(50.0f, 0.0f, 50.0f, 50.0f);

    child1->flags |= WidgetFlags::Focusable;
    child2->flags |= WidgetFlags::Focusable;

    widget_add_child(parent, child1);
    widget_add_child(parent, child2);

    EventDispatcher dispatcher;
    dispatcher.root = parent;

    dispatcher.set_focus(child1);

    // Arrow key should navigate within focus group
    // (The actual arrow navigation is application-specific)
    TEST_ASSERT_EQ(dispatcher.focused, child1);
}

